create table dirkspzm32.bde_fa_auftrag_log (
    sid                  varchar2(2 char) default '01' not null enable,
    firma_nr             number(2, 0) default 1 not null enable,
    fa_log_id            number(*, 0) not null enable,
    leitzahl             number(*, 0) not null enable,
    fa_ag                number(*, 0) not null enable,
    fa_upos              number(*, 0) not null enable,
    freig_status         varchar2(3 char) not null enable,
    log_status           number(1, 0) not null enable,
    message              varchar2(255 char),
    ag_soll_mg           number(*, 5),
    ag_ist_mg            number(*, 5),
    anz_erz_transporte   number(*, 5),
    lam_menge_rest       number(*, 5),
    created_date         date not null enable,
    created_login_id     number(*, 0) not null enable,
    last_change_date     date not null enable,
    last_change_login_id number(*, 0) not null enable
);

alter table dirkspzm32.bde_fa_auftrag_log
    add constraint pk_bde_fa_auftrag_log primary key ( fa_log_id )
        using index enable;


